(function(w){"use strict";const ID="percent";function compute(x){const a=Number(x.a),b=Number(x.b),mode=x.mode||"part";if(!Number.isFinite(a)||!Number.isFinite(b))return{error:"숫자를 올바르게 입력해 주세요."};if(mode==="part"){if(b===0)return{error:"전체값은 0이 될 수 없습니다."};return{value:a/b*100,label:"전체값에서 차지하는 비율",unit:"%"}}if(mode==="of")return{value:b*a/100,label:`${a}%에 해당하는 값`,unit:""};if(mode==="change"){if(a===0)return{error:"기준값은 0이 될 수 없습니다."};return{value:(b-a)/Math.abs(a)*100,label:"증감률",unit:"%"};}return{error:"계산 유형을 확인해 주세요."}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label for="hm-percent-mode">계산 유형</label><select id="hm-percent-mode" class="hm-calc-select"><option value="part">A는 B의 몇 %?</option><option value="of">A%는 B의 얼마?</option><option value="change">A에서 B로 증감률</option></select></div><div class="hm-calc-grid-2"><div class="hm-calc-field"><label for="hm-percent-a">A 값</label><input id="hm-percent-a" class="hm-calc-input" inputmode="decimal" placeholder="예: 20"></div><div class="hm-calc-field"><label for="hm-percent-b">B 값</label><input id="hm-percent-b" class="hm-calc-input" inputmode="decimal" placeholder="예: 200"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button><button type="button" class="hm-calc-btn secondary">초기화</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const mode=root.querySelector("select"),[a,b]=root.querySelectorAll("input"),[go,reset]=root.querySelectorAll("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({a:api.parseNumber(a.value),b:api.parseNumber(b.value),mode:mode.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard(r.label,api.formatNumber(r.value,4)+r.unit));});reset.addEventListener("click",()=>{a.value=b.value="";api.setMessage(msg,"");api.clearResult(res);a.focus();});}w.HM_CALC.register(ID,{compute,render});})(window);
